verification.command:
set -e
h1=$(grep -nE '^## \[' CHANGELOG.md | sed -n '1p')
h2=$(grep -nE '^## \[' CHANGELOG.md | sed -n '2p')
h3=$(grep -nE '^## \[' CHANGELOG.md | sed -n '3p')
printf '%s\n' "$h1" | grep -Fq '## [Unreleased]' || { echo "1st heading not [Unreleased]: $h1"; exit 1; }
printf '%s\n' "$h2" | grep -Eq '## \[0\.8\.0\] - 2026-07-20' || { echo "2nd heading not [0.8.0] - 2026-07-20: $h2"; exit 1; }
printf '%s\n' "$h3" | grep -Fq '## [0.7.0]' || { echo "3rd heading not [0.7.0]: $h3"; exit 1; }
u=$(awk '/^## \[Unreleased\]/{f=1;next} /^## \[0\.8\.0\]/{f=0} f&&/^### /{print}' CHANGELOG.md)
test -z "$u" || { echo "[Unreleased] not empty: $u"; exit 1; }
echo "E02 PASS: [Unreleased](empty) -> [0.8.0] - 2026-07-20 -> [0.7.0]"

set -e
sec=$(awk '/^## \[0\.8\.0\]/{f=1;next} /^## \[0\.7\.0\]/{f=0} f' CHANGELOG.md)
printf '%s\n' "$sec" | grep -Fiq 'minor' || { echo "no MINOR tier named"; exit 1; }
printf '%s\n' "$sec" | grep -Fiq 'constitutional' || { echo "roll-up dropped the constitutional entry"; exit 1; }
printf '%s\n' "$sec" | grep -Fiq 'blocking_findings' || { echo "schema-change not disclosed"; exit 1; }
echo "E03 PASS: [0.8.0] names MINOR tier, preserves phase-006 entries, discloses the blocking_findings schema change"

set -e
exp=$(python3 -c 'import json;print(json.load(open("NIZAM.json"))["framework"]["version"])')
meta=$(grep -oE 'name="framework-version" content="[0-9.]+"' docs/guide/index.html | grep -oE '[0-9]+\.[0-9]+\.[0-9]+' | head -1)
foot=$(grep -oE 'id="footer-version">[0-9.]+' docs/guide/index.html | grep -oE '[0-9]+\.[0-9]+\.[0-9]+' | head -1)
test "$exp" = "0.8.0" || { echo "NIZAM.json not 0.8.0 ($exp)"; exit 1; }
test "$meta" = "$exp" || { echo "guide meta $meta != $exp"; exit 1; }
test "$foot" = "$exp" || { echo "guide footer $foot != $exp"; exit 1; }
echo "E05 PASS: guide meta=$meta footer=$foot == NIZAM.json $exp (C10 anchor consistent)"

set -e
head=$(git show 707a3f5:CONTEXT.md | awk -F': ' '/^version:/{print $2; exit}')
now=$(awk -F': ' '/^version:/{print $2; exit}' CONTEXT.md)
test "$now" = "0.8.0" || { echo "CONTEXT.md version not 0.8.0 ($now)"; exit 1; }
python3 -c "
def t(v): return tuple(int(x) for x in v.strip().split('.'))
assert t('$now') > t('$head'), 'not a strict increase: $head -> $now'"
awk 'c<2{print} /^---/{c++}' CONTEXT.md | grep -Fq '"0.8.0"' || { echo "no 0.8.0 change_log entry"; exit 1; }
echo "E06 PASS: CONTEXT.md 0.7.0 -> 0.8.0 with a matching change_log entry"

set -e
n=$(grep -cE 'v0\.7\.0' README.md || true)
test "$n" -eq 0 || { echo "README still has $n v0.7.0 reference(s)"; grep -nE 'v0\.7\.0' README.md; exit 1; }
grep -Fq 'v0.8.0' README.md || { echo "README missing v0.8.0"; exit 1; }
echo "E07 PASS: README fully re-pinned to v0.8.0 (zero v0.7.0 remaining)"

set -e
f=.agent/evidence/059-release-readiness-checklist.md
test -f "$f" || { echo "no checklist"; exit 1; }
for i in 1 2 3 4 5 6 7 8; do grep -Eq "^$i\. " "$f" || { echo "missing item $i"; exit 1; }; done
grep -E '^7\. ' "$f" | grep -Fq 'PENDING -- human-gated (H-FRAMEWORK-RELEASE)' || { echo "item 7 not pinned PENDING"; exit 1; }
grep -E '^8\. ' "$f" | grep -Fq 'PENDING -- human-gated (H-FRAMEWORK-RELEASE)' || { echo "item 8 not pinned PENDING"; exit 1; }
for i in 1 2 3 4 5 6; do grep -E "^$i\. " "$f" | grep -Eq '\.agent/|\.md|\.json|\.html|SUMMARY|NDEBT' || { echo "item $i lacks an evidence citation"; exit 1; }; done
if grep -E '^[1-6]\. ' "$f" | grep -Fq 'PENDING'; then echo "an evidenced item 1-6 is still PENDING"; exit 1; fi
echo "E08 PASS: checklist items 1-6 evidenced; items 7-8 pinned PENDING (human-gated)"

set -e
grep -Fq 'C1-C15' NIZAM.json || { echo "NIZAM.json not synced to C1-C15"; exit 1; }
grep -Fq '15 passed, 0 failed' tools/README.md || { echo "README not synced to 15 passed"; exit 1; }
grep -Eq 'C1.C15' tools/README.md || { echo "README not synced to C1-C15"; exit 1; }
grep -Fq '| C14 |' tools/README.md || { echo "README missing C14 row"; exit 1; }
grep -Fq '| C15 |' tools/README.md || { echo "README missing C15 row"; exit 1; }
if grep -Eq 'all 13 checks|checks C1-C10' tools/validate.sh; then echo "stale count remains in validate.sh"; exit 1; fi
grep -Fq 'all 15 checks' tools/validate.sh || { echo "validate.sh usage not synced to 15"; exit 1; }
echo "E12 PASS: check-count synced to 15 (C1-C15) across NIZAM.json, tools/README.md, validate.sh"
